// Simulate reading 4 holding registers (FC03) from a Modbus TCP slave.
// Replace this node with a real modbus-read node when a device is available.
// Holding registers:
//   HR0 - Voltage (V)  : 220-240
//   HR1 - Current (A)  : 0-25 (scaled x10, raw=0..250)
//   HR2 - Power (W)    : 0-6000
//   HR3 - Temperature  : 20-80 (°C)
var voltage   = 220 + Math.random() * 20;
var currentRaw = Math.round((Math.random() * 25) * 10); // scaled
var power     = Math.round(voltage * (currentRaw / 10));
var temp      = 20 + Math.random() * 60;

msg.registers = {
    hr0: Math.round(voltage),
    hr1: currentRaw,
    hr2: power,
    hr3: Math.round(temp)
};
return msg;

var r = msg.registers;
var now = Date.now() * 1e6;
msg.payload = JSON.stringify([
    {"bn": "modbus-device:", "bt": now,
     "n": "hr0", "u": "V",   "v": r.hr0},
    {"n": "hr1", "u": "A",   "v": r.hr1 / 10},
    {"n": "hr2", "u": "W",   "v": r.hr2},
    {"n": "hr3", "u": "Cel", "v": r.hr3}
]);
msg.topic = "m/a1c51744-3317-48e2-9eef-4df37f68b9d1/c/82f1d080-b1ce-41b7-aef2-62b270e551e7/data";
return msg;
